def _resolve_dynamic_defaults(ctx: Context) -> None:
    """Resolve dynamic (dict-based) option defaults.

    This runs as a second pass after every parameter has been parsed
    from the command line, environment variables, and the default map,
    so that a dynamic default can depend on the final values of other
    options. Only options whose value still comes from
    :attr:`ParameterSource.DEFAULT` are affected.
    """
    for param in ctx.command.get_params(ctx):
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore[arg-type]
            continue

        resolved = None

        for source_decl, mapping in param.default.items():
            source_param = None

            for candidate in ctx.command.get_params(ctx):
                if isinstance(candidate, Option) and source_decl in (
                    *candidate.opts,
                    *candidate.secondary_opts,
                ):
                    source_param = candidate
                    break

            if source_param is None:
                continue

            key = str(ctx.params.get(source_param.name))

            if key in mapping:
                resolved = mapping[key]

        if resolved is None:
            continue

        value = param.type_cast_value(ctx, resolved)

        if param.callback is not None:
            value = param.callback(ctx, param, value)

        if param.expose_value:
            ctx.params[param.name] = value  # type: ignore[index]


